                "<table class='sum-table'><thead><tr><th>Section</th><th>Prose or bullets?</th></tr></thead><tbody><tr><td>Objet</td><td>Single sentence (prose)</td></tr><tr><td>Contexte</td><td>Prose paragraphs</td></tr><tr><td>Faits / Données</td><td>Prose with embedded statistics</td></tr><tr><td>Conclusions</td><td>Prose (analytical)</td></tr><tr><td>Recommandations</td><td>Bullet points (parallel infinitives)</td></tr></tbody></table>"
